SELECT total_prize_fund
FROM prize_distribution
WHERE draw_id = 0 AND category_id = 1;

SELECT draw_id, SUM(total_prize_fund) AS total_distributed_fund
FROM prize_distribution
GROUP BY draw_id;

SELECT SUM(total_prize_fund) AS total_distributed_fund
FROM prize_distribution
WHERE draw_id = 0;

SELECT SUM(prize_per_winner) AS total_prize_per_winner
FROM prize_categories
WHERE draw_id = 1;

SELECT category_name
FROM prize_categories
WHERE category_id = 0;

SELECT winner_id, amount_awarded, date_awarded
FROM winners_history
WHERE claim_status = 'unclaimed';

SELECT draw_date, total_prize_fund
FROM lottery_draws
ORDER BY draw_date DESC;

SELECT total_prize_amount
FROM winners
WHERE winner_id = 1;
